package com.example.webhook;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;

import java.util.Map;
import java.util.concurrent.CompletableFuture;

@SpringBootApplication
@RestController
@RequestMapping("/webhook")
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    @PostMapping("/process")
    public ResponseEntity<String> processWebhook(@RequestBody Map<String, Object> payload) {
        try {
            String url = (String) payload.get("url");
            String method = (String) payload.getOrDefault("method", "GET");
            Map<String, String> headers = (Map<String, String>) payload.get("headers");
            Object body = payload.get("body");

            HttpEntity<Object> requestEntity = createRequestEntity(body, headers);
            HttpMethod httpMethod = HttpMethod.valueOf(method.toUpperCase());

            ResponseEntity<String> response = restTemplate.exchange(
                    url,
                    httpMethod,
                    requestEntity,
                    String.class
            );

            return ResponseEntity.ok()
                    .contentType(MediaType.APPLICATION_JSON)
                    .body(response.getBody());
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("{\"error\": \"" + e.getMessage() + "\"}");
        }
    }

    private HttpEntity<Object> createRequestEntity(Object body, Map<String, String> headers) {
        HttpHeaders httpHeaders = new HttpHeaders();
        if (headers != null) {
            headers.forEach(httpHeaders::add);
        }

        if (body != null) {
            httpHeaders.setContentType(MediaType.APPLICATION_JSON);
        }

        return new HttpEntity<>(body, httpHeaders);
    }

    @PostMapping("/async-process")
    public CompletableFuture<ResponseEntity<String>> processWebhookAsync(@RequestBody Map<String, Object> payload) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                String url = (String) payload.get("url");
                String method = (String) payload.getOrDefault("method", "GET");
                Map<String, String> headers = (Map<String, String>) payload.get("headers");
                Object body = payload.get("body");

                HttpEntity<Object> requestEntity = createRequestEntity(body, headers);
                HttpMethod httpMethod = HttpMethod.valueOf(method.toUpperCase());

                ResponseEntity<String> response = restTemplate.exchange(
                        url,
                        httpMethod,
                        requestEntity,
                        String.class
                );

                return ResponseEntity.ok()
                        .contentType(MediaType.APPLICATION_JSON)
                        .body(response.getBody());
            } catch (Exception e) {
                return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                        .body("{\"error\": \"" + e.getMessage() + "\"}");
            }
        });
    }

    public static void main(String[] args) {
        SpringApplication.run(WebhookHandler.class, args);
    }
}